#include <bits/stdc++.h>
using namespace std;
int n,a[80004];
long long ans;
stack<int> s;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++){
        while(s.size() && a[s.top()]<=a[i])
            ans+=i-s.top()-1,s.pop();
        s.push(i);
    }
    while(s.size())
        ans+=n-s.top(),s.pop();
    printf("%lld",ans);
    return 0;
}
